ReportUtil = {}

function ReportUtil:reportLookedAdGetActor(player, itemId)
    GameAnalytics:design(player.userId, 1, { "hide_getitem_ad", "itemId " .. itemId })
    LogUtil.log("ReportUtil:reportLookedAdGetActor " .. itemId)
end

function ReportUtil:reportAdDisplay(player, adType)
    GameAnalytics:design(player.userId, 1, { "game_shop_ad_view", "adType " .. adType , "displayTime " .. DateUtil.getDateString(os.time())})
    LogUtil.log("ReportUtil:reportAdDisplay " .. adType)
    --print("ReportUtil:reportAdDisplay " .. adType)
end


return ReportUtil
